		function ValSeguridad()
{
	var param;	

	var np = new NomadProxy("", ut);
	var nSQL = np.SQLService();

	param = nSQL.GetOBJ(Ctrl("main").getResource("QRY_ORG_SEGURIDAD"), ""); 		
	if(param.oi_clase_org == "0")
	{
		alert("No se ha establecido el Organigrama de Seguridad");
		return false;	
	}

	//if(Ctrl('oi_clase_org') != undefined)
		Ctrl('oi_clase_org').SetXValue(param.oi_clase_org);

	return true;	
}

function ToList()
{                
	if (parseInt(Ctrl("iter-size").GetXValue(),10)<=400)
		Ctrl("LISTA").DoEvent("showList");
	else
		alert("Demasiados registros para ser mostrados en una lista.");
}

function LoadForm()
{  
	if (Ctrl('main').GetMode()!="LIST")
	{		
			if(Ctrl('main').GetMode()!="NEW" && Ctrl('main').GetMode()!="REINGRESAR")
			{ 
				CargarSuperior();   
	    	CargarDepartamento();
			}
	}  

    if(Ctrl('Defecto') != undefined && Ctrl('oi_indic_activo') != undefined && Ctrl('oi_indic_activo').GetXValue() == '4')
    {
    	CtrlEnabled('Defecto',false);
    }

  //var confidencial = habilitarConfidenciales();

	CtrlEnabled('f_inicio_contrato', false);
	CtrlEnabled('f_fin_contrato', false);
	CtrlEnabled('e_duracion_ctrato', false);
	CtrlEnabled('oi_unidad_tiempo', false);

	if (Ctrl('main').GetMode()=="EDIT")
	{		
		var contratista;
		var np = new NomadProxy("", ut);
		var nSQL = np.SQLService();

		contratista = nSQL.GetOBJ(Ctrl("main").getResource("QRY_NRO_LEGAJO"), "<PARAM oi_empresa=\""+Ctrl("oi_empresa").GetXValue()+"\" />"); 		
		Ctrl("l_contratista").SetXValue(contratista.l_contratista);				

		if (Ctrl('l_contratista').GetCValue() == "1")
		{
			CtrlEnabled('oi_empresa_vinc', true);		
		}
		else
		{
			CtrlEnabled('oi_empresa_vinc', false);
		}

		if (Ctrl('f_ingreso'))
			if (Ctrl('f_ingreso').GetCValue() == '/1/1010')
				Ctrl('f_ingreso').SetXValue('');    


		if(Ctrl('img_ojo') != undefined)
		{
		    if(Ctrl('l_confidencial') == undefined )
		    { 
		    	CtrlEnabled('REMUN_PER',false); 
		    	ocultarConfidenciales();   
		    }   
		    else if(!Ctrl('img_ojo').GetEnabled() &&  Ctrl('l_confidencial').GetXValue() == "1")
				{
					CtrlEnabled('REMUN_PER',false);
					ocultarConfidenciales();
				}                               
				else
				{
					CtrlEnabled('REMUN_PER',true);
				}
		}			
	}	

	if (Ctrl('main').GetMode()=="SHOW")  	
	{ 
		//if(confidencial != "ninguno")  
		if(Ctrl('img_ojo') != undefined)		
		{ 
			if(Ctrl('l_confidencial') == undefined )
		  {                  
				CtrlEnabled('REMUN_PER',false);    
				ocultarConfidenciales();
		  }
		  //else if(confidencial == "noconf" &&  Ctrl('l_confidencial').GetXValue() == "1")
 			else if(!Ctrl('img_ojo').GetEnabled() &&  Ctrl('l_confidencial').GetXValue() == "1")			
			{
				CtrlEnabled('REMUN_PER',false);
				ocultarConfidenciales();
			}                               
			else
			{
				CtrlEnabled('REMUN_PER',true);
			}
		}

		Ctrl('f_hid').SetXValue(datetime2str(NowDate()));	
		return true;
	}
	if (Ctrl('main').GetMode()=="NEW")
	{
		CtrlEnabled('oi_empresa_vinc', false);
	}
}

function LoadPersonal(me)
{
	var fecha;	

	var np = new NomadProxy("", ut);
	var nSQL = np.SQLService();

	if (Ctrl('main').GetMode()=="NEW")
	{
		if (Ctrl('oi_personal').GetXValue() !="")
		{
			fecha = nSQL.GetOBJ(Ctrl("main").getResource("QRY_F_ANTIG"), "<PARAM oi_personal=\""+Ctrl("oi_personal").GetXValue()+"\" />"); 					
			if(fecha.f_computada)
			{
				if(fecha.f_computada != '000000')
				{
					Ctrl("f_antiguedad_rec").SetXValue(fecha.f_computada);
					return true;
				}				
			}
		}
		else
		{
			Ctrl("f_antiguedad_rec").SetXValue("");					
		}
	}  
}

function LoadEmpresa(me)
{
	var legajo;	

	var np = new NomadProxy("", ut);
	var nSQL = np.SQLService();

	if (me.GetCValue() != "")
	{
		CtrlEnabled('oi_funcion', true);		
		legajo = nSQL.GetOBJ(Ctrl("main").getResource("QRY_NRO_LEGAJO"), "<PARAM oi_empresa=\""+Ctrl("oi_empresa").GetXValue()+"\" />"); 		
		Ctrl("e_numero_legajo").SetXValue(legajo.e_numero_legajo);
		Ctrl("l_contratista").SetXValue(legajo.l_contratista);				
		if (legajo.oi_art != null)
			Ctrl("oi_art").SetXValue(legajo.oi_art);				
		else
		 Ctrl("oi_art").SetXValue("");				
	}
	else
	{		
		Ctrl('oi_funcion').SetCValue("");		
		Ctrl('l_contratista').SetCValue("0");
		Ctrl('e_numero_legajo').SetCValue("");
		Ctrl('oi_art').SetCValue("");
		CtrlEnabled('oi_funcion', false);						
	}

 if (Ctrl('l_contratista').GetCValue() == "1")
 {
 		CtrlEnabled('oi_empresa_vinc', true);		
 }
 else
 {
 		CtrlEnabled('oi_empresa_vinc', false);
 }
}

function habilitar_fec_contrato(me)
{
	if (me.GetCValue() != "")
	{								
		CtrlEnabled('f_inicio_contrato', true);
		CtrlEnabled('f_fin_contrato', true);
		CtrlEnabled('e_duracion_ctrato', true);
		CtrlEnabled('oi_unidad_tiempo', true);
	}
	else
	{
		CtrlEnabled('f_inicio_contrato', false);
		CtrlEnabled('f_fin_contrato', false);
		CtrlEnabled('e_duracion_ctrato', false);
		CtrlEnabled('oi_unidad_tiempo', false);
	}
}


function habilitar_fec_cc(me)
{
	if (me.GetCValue() != "")
	{				
		CtrlEnabled('f_desde_ccosto', true);				
	}
	else
	{
		CtrlEnabled('f_desde_ccosto', false);				
	}

}

function habilitar_fec_em(me)
{
	if (me.GetXValue() != "")
	{				
		CtrlEnabled('f_ingreso_equipo', true);				
	}
	else
	{
		CtrlEnabled('f_ingreso_equipo', false);				
	}

}           

function VerPersona()
{                                   
	if(Ctrl("main").GetMode()=="LIST")     
		{
		var np = new NomadProxy("", ut);
		var nSQL = np.SQLService();
		var personal = nSQL.GetOBJ(Ctrl("main").getResource("QRY_PERSONAL"), "<PARAM oi_personal_emp=\""+Ctrl("LIST").GetSelectAttrValue("id")+"\" />"); 	
		getFormInMain("NucleusRH.Base.Personal.Legajo.flow", "ORGANIGRAMA",  "<PERSONAL VALUE=\""+personal.oi_personal.toString()+"\" />", false);     
		}
	else
		getFormInMain("NucleusRH.Base.Personal.Legajo.flow", "ORGANIGRAMA",  "<PERSONAL VALUE=\""+Ctrl("oi_personal").GetXValue()+"\" />", false);
}

function VerEmpresa()
{         
	if(Ctrl("main").GetMode()=="LIST")
		getFormInMain("NucleusRH.Base.Organizacion.Empresas.NAV.flow", "filter",  "<EMPRESA VALUE=\""+Ctrl("LIST").GetSelectAttrValue("oi_empresa")+"\" />", false);
	else
		getFormInMain("NucleusRH.Base.Organizacion.Empresas.NAV.flow", "filter",  "<EMPRESA VALUE=\""+Ctrl("oi_empresa").GetXValue()+"\" />", false);
} 

function Validar()
{
	var param= new NomadXML("PARAM");
	param.SetAttr("oi_empresa",Ctrl("oi_empresa").GetXValue());

	var np = new NomadProxy();
	var nSQL = np.SQLService();               

	var result = nSQL.GetOBJ(Ctrl("main").getResource("QRY_AFIP"), param.ToString()); 

	if(result.l_alta_afip && result.l_alta_afip.toString()==1 && Ctrl("c_alta_afip").GetXValue()=="")
		{
			alert("Es requerido el número de alta de Afip para la Empresa a la cual pertenece el Legajo.");
			Ctrl("c_alta_afip").SetFocus();
			return false;
		}	
	else
		return true;
}

function ValidarNum()
{ 
   if(Validar())
	{
		var numero = Ctrl("c_alta_afip").GetXValue();       

		if(numero!="" && (!/^([0-9])*$/.test(numero)))
			{
				alert("El valor del campo 'Número de Alta AFIP' debe ser un número entero");
				Ctrl("c_alta_afip").SetFocus();
				return false;
			}	
		else
			return true;
	}
	else
		return false;

}                       




