function CargarSuperior()
{                                                   
	var superior;	 	
	var np = new NomadProxy("", ut);
	var nSQL = np.SQLService();

	superior = nSQL.GetOBJ(Ctrl("main").getResource("QRY_SUPERIOR"), "<PARAM oi_personal_emp=\""+Ctrl("oi_personal_emp").GetXValue()+"\" />"); 		

	Ctrl('d_superior').SetXValue(superior.d_iniciales);
}   

function CargarDepartamento()
{                                                   
	var posicion;	 	
	var np = new NomadProxy("", ut);
	var nSQL = np.SQLService();

	posicion = nSQL.GetOBJ(Ctrl("main").getResource("QRY_DEPARTAMENTO"), "<PARAM oi_posicion=\""+Ctrl("oi_posicion_ult").GetXValue()+"\" />"); 		

	if(posicion.oi_departamento)
		Ctrl('oi_departamento').SetXValue(posicion.oi_departamento); 
	if(posicion.oi_sector)
		Ctrl('oi_sector').SetXValue(posicion.oi_sector);
}               


//Se guarda de nuevo el oi_categoria, que se puso en '' para ocultarlo al usuario no admin de confidenciales
function guardarDatosConfidenciales()
{     
		if (Ctrl('main').GetMode()=="EDIT")
		{
				if (Ctrl('hidden_oi_cat_ult').GetXValue() != "" && Ctrl('oi_categoria_ult').GetXValue() == "")
				{ 
			 		Ctrl('oi_categoria_ult').SetXValue(Ctrl('hidden_oi_cat_ult').GetXValue());
			 	}
		}	 
		else if (Ctrl('main').GetMode()=="NEW")
		{
			if (Ctrl('oi_categoria_ult').GetXValue() != "")
			{
					Ctrl('hidden_oi_cat_ult').SetXValue(Ctrl('oi_categoria_ult').GetXValue());							  
			}
		}     
		else if (Ctrl('main').GetMode()=="REINGRESAR")
		{
			if (Ctrl('oi_categoria_ult').GetXValue() != "")
			{
					Ctrl('hidden_oi_cat_ult').SetXValue(Ctrl('oi_categoria_ult').GetXValue());							  
			}
		}
	  return true;
}  


//Esta funcion es llamada cuando el usuario no administra confidenciales  
function ocultarConfidenciales()
{

	if(Ctrl('n_ult_remun') != undefined)
		document.getElementById("n_ult_remun").style.visibility = "hidden";

	if(Ctrl('f_desde_remun') != undefined)
		document.getElementById("f_desde_remun").style.visibility = "hidden";
	if(Ctrl('f_desde_categoria') != undefined)
		document.getElementById("f_desde_categoria").style.visibility = "hidden";

	//guarda temporalmente el valor que podia tener el oi_categoria_ult en el control hidden_oi_cat_ult
	if(Ctrl('oi_categoria_ult') != undefined)
	{ 
		if (Ctrl('oi_categoria_ult').GetXValue() != "")
		{  
			Ctrl('hidden_oi_cat_ult').SetXValue(Ctrl('oi_categoria_ult').GetXValue()); 
		} 

		Ctrl('oi_categoria_ult').SetXValue("");
    }
}
